import{_ as a,o as r,c as i,a2 as t}from"./chunks/framework.BFZItJIV.js";const p=JSON.parse('{"title":"關於 S3 For XunRuiCMS","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/about.md","filePath":"zh-TW/about.md"}'),l={name:"zh-TW/about.md"};function o(n,e,h,s,u,c){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="關於-s3-for-xunruicms" tabindex="-1">關於 S3 For XunRuiCMS <a class="header-anchor" href="#關於-s3-for-xunruicms" aria-label="Permalink to &quot;關於 S3 For XunRuiCMS&quot;">​</a></h1><h2 id="項目簡介" tabindex="-1">項目簡介 <a class="header-anchor" href="#項目簡介" aria-label="Permalink to &quot;項目簡介&quot;">​</a></h2><p>S3 For XunRuiCMS 是為迅睿CMS系統提供 AWS S3 雲存儲支持的插件。</p><h2 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h2><ul><li>完整的文件上傳/下載管理功能</li><li>支持大文件分片上傳和斷點續傳</li><li>與迅睿CMS文件管理系統無縫集成</li><li>完善的錯誤處理和日誌記錄</li></ul><h2 id="安裝要求" tabindex="-1">安裝要求 <a class="header-anchor" href="#安裝要求" aria-label="Permalink to &quot;安裝要求&quot;">​</a></h2><ul><li>PHP 7.4 或更高版本</li><li>迅睿CMS 5.0+</li></ul><h2 id="安裝方式" tabindex="-1">安裝方式 <a class="header-anchor" href="#安裝方式" aria-label="Permalink to &quot;安裝方式&quot;">​</a></h2><p>通過迅睿CMS插件市場直接安裝</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><ol><li>安裝插件後，在迅睿CMS後台配置 AWS S3 相關信息</li><li>啟用插件後，即可在迅睿CMS文件管理中使用 AWS S3 作為存儲</li></ol><h2 id="文檔站點技術棧" tabindex="-1">文檔站點技術棧 <a class="header-anchor" href="#文檔站點技術棧" aria-label="Permalink to &quot;文檔站點技術棧&quot;">​</a></h2><p>本文檔站點基於以下技術構建：</p><p><strong>VitePress</strong> - 靜態站點生成器，版本 ^1.0.0</p><ul><li>官網：<a href="https://vitepress.dev/" target="_blank" rel="noreferrer">https://vitepress.dev/</a></li><li>許可證：MIT License</li></ul><p><strong>vitepress-plugin-image-viewer</strong> - 圖片查看器插件，版本 ^1.1.6</p><ul><li>官網：<a href="https://github.com/noonnightrocker/vitepress-plugin-image-viewer" target="_blank" rel="noreferrer">https://github.com/noonnightrocker/vitepress-plugin-image-viewer</a></li><li>許可證：MIT License</li></ul><h2 id="致謝" tabindex="-1">致謝 <a class="header-anchor" href="#致謝" aria-label="Permalink to &quot;致謝&quot;">​</a></h2><p>感謝 Vue.js、Vite、VitePress 等開源項目的貢獻者。</p><h2 id="作者信息" tabindex="-1">作者信息 <a class="header-anchor" href="#作者信息" aria-label="Permalink to &quot;作者信息&quot;">​</a></h2><ul><li>作者：陳延德</li><li>郵箱：<a href="mailto:me@chenyande.com" target="_blank" rel="noreferrer">me@chenyande.com</a></li><li>站點：<a href="https://www.chenyande.com" target="_blank" rel="noreferrer">chenyande.com</a></li></ul><h2 id="許可證" tabindex="-1">許可證 <a class="header-anchor" href="#許可證" aria-label="Permalink to &quot;許可證&quot;">​</a></h2><p>本項目採用 Apache License 2.0 授權</p><p>Copyright © 2025 - 2026 陳延德. 保留所有權利</p>',24)])])}const m=a(l,[["render",o]]);export{p as __pageData,m as default};
